namespace reaction {
    class ObserverNode;
    class ObserverGraph;
    using BatchId = std::string;
}

namespace test_reaction {

bool test_batch_operations() {
    // 1. Create observer nodes
    auto node1 = std::make_shared<reaction::ObserverNode>();
    auto node2 = std::make_shared<reaction::ObserverNode>();
    auto node3 = std::make_shared<reaction::ObserverNode>();

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Create batch ID
    reaction::BatchId batchId = "batch_test_001";

    // 4. Register nodes to batch
    graph.registerNodeToBatch(node1, batchId);
    graph.registerNodeToBatch(node2, batchId);
    graph.registerNodeToBatch(node3, batchId);

    // 5. Verify nodes are in batch
    if (!graph.isNodeInBatch(node1, batchId) ||
        !graph.isNodeInBatch(node2, batchId) ||
        !graph.isNodeInBatch(node3, batchId)) {
        return false;
    }

    // 6. Unregister batch
    graph.unregisterBatch(batchId);

    // 7. Verify nodes are no longer in batch
    if (graph.isNodeInBatch(node1, batchId) ||
        graph.isNodeInBatch(node2, batchId) ||
        graph.isNodeInBatch(node3, batchId)) {
        return false;
    }

    // 8. Return success status
    return true;
}

}  // namespace test_reaction
```

**Key Implementation Details:**

1. **Node Creation**: Uses `std::make_shared` to create observer nodes with automatic memory management
2. **Singleton Access**: Retrieves the singleton instance of `ObserverGraph` using `getInstance()`
3. **Batch Operations**: 
   - `registerNodeToBatch()` adds nodes to specified batch
