/**
 * Function: Test transactional observer updates
 *
 * @param nodeName Name for the node to update
 * @return bool Whether transactional update succeeded (no cycle created)
 */
bool test_transactional_update(const std::string& nodeName) {
    try {
        // 1. Create observer nodes
        auto sourceNode = std::make_shared<TestTransactionalObserver>("source");
        auto targetNode = std::make_shared<TestTransactionalObserver>("target");
        auto updateNode = std::make_shared<TestTransactionalObserver>(nodeName);

        // 2. Get observer graph instance
        auto& graph = reaction::ObserverGraph::getInstance();

        // 3. Set up initial relationship: source -> target
        graph.addObserver(sourceNode, targetNode);

        // 4. Notify target and verify relationship works
        sourceNode->valueChanged(true);
        if (!targetNode->wasChanged()) {
            return false; // Relationship not working
        }

        // 5. Reset observers for next test phase
        sourceNode->reset();
        targetNode->reset();
        updateNode->reset();

        // 6. Attempt transactional update that would create cycle
        // This would create: source -> target -> updateNode -> source (cycle)
        graph.beginTransaction();
        graph.addObserver(targetNode, updateNode);
        graph.addObserver(updateNode, sourceNode); // This creates potential cycle

        // 7. Check if cycle was detected and prevented transactionally
        bool cycleDetected = false;
        try {
            graph.commitTransaction();
        } catch (const std::runtime_error& e) {
            if (std::string(e.what()).find("cycle") != std::string::npos) {
                cycleDetected = true;
            }
        }

        // 8. Notify target again to verify original relationship preserved
        sourceNode->valueChanged(true);

        // 9. Verify original relationship is preserved
        if (!targetNode->wasChanged()) {
            return false; // Original relationship broken
        }

        // 10. Return success status
        return cycleDetected && !updateNode->wasChanged();

    } catch (...) {
        return false;
    }
}

