namespace test_reaction {

class NamedObserverNode : public reaction::ObserverNode {
private:
    std::string m_name;

public:
    explicit NamedObserverNode(std::string name) : m_name(std::move(name)) {}

    const std::string& name() const { return m_name; }
};

struct ObserverCollectionSummary {
    std::size_t totalObservers;
    bool containsDirectObserver;
    bool containsTransitiveObserver;
};

ObserverCollectionSummary test_observer_collection() {
    // Create observer nodes
    auto direct_observer = std::make_shared<NamedObserverNode>("direct");
    auto transitive_observer = std::make_shared<NamedObserverNode>("transitive");
    auto source_node = std::make_shared<NamedObserverNode>("source");

    // Get observer graph instance
    auto& observer_graph = reaction::ObserverGraph::getInstance();

    // Register nodes
    observer_graph.registerNode(direct_observer);
    observer_graph.registerNode(transitive_observer);
    observer_graph.registerNode(source_node);

    // Set up direct observer relationship
    source_node->addDirectObserver(direct_observer);

    // Set up transitive observer relationship (through direct observer)
    direct_observer->addDirectObserver(transitive_observer);

    // Create node set for collecting observers
    reaction::NodeSet collected_observers;

    // Collect observers from source node
    observer_graph.collectObservers(source_node, collected_observers);

    // Prepare summary
    ObserverCollectionSummary summary{
        collected_observers.size(),
        collected_observers.contains(direct_observer),
