    SBOResource<LargePayload> largeResource(makeLargePayload());

    // 4. Update small resource value
    bool updateReportedChange = (smallResource.update(SmallPayload{updatedSmall}) != false);

    // 5. Get storage information for small resource
    auto smallInfo = smallResource.getStorageInfo();

    // 6. Get storage information for large resource
    auto largeInfo = largeResource.getStorageInfo();

    // 7. Return aggregated storage status
    return SboStorageStatus{
        updateReportedChange,
        smallInfo.isUsingSBO,
        smallInfo.stackUsage,
        largeInfo.initialized,
        largeInfo.isUsingSBO
    };
